			bd.writeBytes("MAIL FROM:"+sender+"\n");

			waitForSuccessResponse(response);

			bd.writeBytes("RCPT :"+recipient+"\n");

			waitForSuccessResponse(response);

			bd.writeBytes("data"+"\n");

			bd.writeBytes("Subject:"+subject+"\n");

			bd.writeBytes(message+"\n.\n");

			waitForSuccessResponse(response);
		}

